and a model contains a mesh containing only one of those primitive types, you get a memory leak. The offending code is in SortByPTypeProcess.cpp. It should be:

---snip-- line 183

```
            if (!(configRemoveMeshes & mesh->mPrimitiveTypes))
            {
                *meshIdx = (unsigned int) outMeshes.size();
                outMeshes.push_back(mesh);
            }
            else
            {
               // the mesh was filtered...delete it
               delete mesh;
               bAnyChanges = true;
            }
```

where the original is:

```
            if (!(configRemoveMeshes & mesh->mPrimitiveTypes))
            {
                *meshIdx = (unsigned int) outMeshes.size();
                outMeshes.push_back(mesh);
            }
            else bAnyChanges = true;
```

